        when (m.tag.tag.text)
        {
            "track" -> 
            {
                if (this._staffIndex > 0)
                {
                    this._writer.outdent()
                }
                if (this._trackIndex > 0)
                {
                    this._writer.outdent()
                }
            }
            "staff" -> 
            {
                if (this._staffIndex > 0)
                {
                    this._writer.outdent()
                }
            }
            "voice" -> 
            {
                if (this._voiceIndex > 0)
                {
                    this._writer.outdent()
                }
            }
            else -> { }
        }
        this._writeComments(m.leadingComments)
        this._writeToken(m.tag.prefix, false)
        this._writeValue(m.tag.tag)
        var newLineAfterMeta: Boolean = true
        if (m.propertiesBeforeArguments)
        {
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(m.properties)))
            {
                this._writer.write(" ")
                this._writeProperties(m.properties!!, false)
            }
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(m.arguments)))
            {
                this._writer.write(" ")
                this._writeValues(m.arguments!!)
            }
        }
        else 
        {
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(m.arguments)))
            {
                this._writer.write(" ")
                this._writeValues(m.arguments!!)
            }
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(m.properties)))
            {
                this._writer.write(" ")
                this._writeProperties(m.properties!!, true)
                newLineAfterMeta = false
            }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(m.trailingComments)))
        {
            this._writer.write(" ")
            this._writeComments(m.trailingComments!!)
        }
        when (m.tag.tag.text)
        {
            "track" -> 
            {
                this._trackIndex++
                this._staffIndex = 0.0
                this._voiceIndex = 0.0
                this._writer.indent()
            }
            "staff" -> 
            {
                this._staffIndex++
                this._voiceIndex = 0.0
                this._writer.indent()
            }
            "voice" -> 
            {
                this._voiceIndex++
                this._writer.indent()
            }
            else -> { }
        }
        if (newLineAfterMeta)
        {
            this._writer.writeLine()
        }
    }
    
    /**
     */
    private fun _writeProperties(properties: com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertiesNode, indent: Boolean): Unit{
        this._writeComments(properties.leadingComments)
        this._writeToken(properties.openBrace, indent)
        if (indent)
        {
            this._writer.indent()
        }
        var first: Boolean = true
        for (p in properties.properties)
        {
            if (!first && !indent)
            {
                this._writer.write(" ")
            }
            this._writeProperty(p)
            first = false
            if (indent)
            {
                this._writer.writeLine()
            }
        }
        if (indent)
        {
            this._writer.outdent()
        }
        this._writeToken(properties.closeBrace, indent)
        this._writeComments(properties.trailingComments)
    }
    
    /**
     */
    private fun _writeProperty(p: com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertyNode): Unit{
        this._writeComments(p.leadingComments)
        this._writeValue(p.property)
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(p.arguments)))
        {
            this._writer.write(" ")
            this._writeValues(p.arguments!!)
        }
        this._writeComments(p.trailingComments)
    }
    
    /**
     */
    private fun _writeValues(values: com.omnifret.gplayer.importer.gplayertex.GPlayerTexArgumentList): Unit{
        this._writeComments(values.leadingComments)
        this._writeToken(values.openParenthesis, false)
        var first: Boolean = true
        for (v in values.arguments)
        {
            if (!first)
            {
                this._writer.write(" ")
            }
            this._writeValue(v)
            first = false
        }
        this._writeToken(values.closeParenthesis, false)
        this._writeComments(values.trailingComments)
    }
    
    /**
     */
    private fun _writeValue(v: com.omnifret.gplayer.importer.gplayertex.IGPlayerTexAstNode?): Unit{
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(v)))
        {
            return
        }
        this._writeComments(v!!.leadingComments)
        when (v!!.nodeType)
        {
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Ident -> 
            {
                this._writer.write(((v as com.omnifret.gplayer.importer.gplayertex.GPlayerTexIdentifier)).text)
            }
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Arguments -> 
            {
                this._writeValues((v as com.omnifret.gplayer.importer.gplayertex.GPlayerTexArgumentList))
            }
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Number -> 
            {
                this._writer.write(((v as com.omnifret.gplayer.importer.gplayertex.GPlayerTexNumberLiteral)).value.toInvariantString())
            }
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.String -> 
            {
                this._writer.writeString(((v as com.omnifret.gplayer.importer.gplayertex.GPlayerTexStringLiteral)).text)
            }
            else -> { }
        }
        this._writeComments(v!!.trailingComments)
    }
    
    /**
     */
    private fun _writeToken(tokenNode: com.omnifret.gplayer.importer.gplayertex.IGPlayerTexAstNode?, newLine: Boolean): Unit{
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(tokenNode)))
        {
            this._writeComments(tokenNode!!.leadingComments)
            when (tokenNode!!.nodeType)
            {
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Dot -> 
                {
                    this._writer.write(".")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Backslash -> 
                {
                    this._writer.write("\\")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.DoubleBackslash -> 
                {
                    this._writer.write("\\\\")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Pipe -> 
                {
                    this._writer.write("|")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.LBrace -> 
                {
                    this._writer.write("{")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.RBrace -> 
                {
                    this._writer.write("}")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.LParen -> 
                {
                    this._writer.write("(")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.RParen -> 
                {
                    this._writer.write(")")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Colon -> 
                {
                    this._writer.write(":")
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexNodeType.Asterisk -> 
                {
                    this._writer.write("*")
                }
                else -> { }
            }
            this._writeComments(tokenNode!!.trailingComments)
            if (newLine)
            {
                this._writer.writeLine()
            }
        }
    }
    
    /**
     */
    private fun _writeComments(comments: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexComment>?): Unit{
        if (!this._comments || !com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(comments)))
        {
            return
        }
        for (c in comments!!)
        {
            var txt: String = c.text
            if (!txt.startsWith(" "))
            {
                txt = """ ${(txt).toTemplate()}"""
            }
            if (c.multiLine)
            {
                if (!txt.endsWith(" "))
                {
                    txt += " "
                }
                this._writer.write("""/*${(txt).toTemplate()}*/""")
            }
            else 
            {
                this._writer.writeLine("""//${(txt).toTemplate()}""")
            }
        }
    }
    
